package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.EMPTY;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.PIPE;
import static org.apache.commons.csv.Constants.SP;
import static org.apache.commons.csv.Constants.TAB;
import java.io.File;
import java.io.FileOutputStream;
import java.io.OutputStreamWriter;
import java.io.Reader;
import java.io.Serializable;
import java.nio.charset.Charset;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_withPath_callsFilesNewBufferedWriterAndReturnsCSVPrinter() throws IOException, ReflectiveOperationException {
        Path mockPath = mock(Path.class);
        StringWriter stringWriter = new StringWriter();
        BufferedWriter bufferedWriter = new BufferedWriter(stringWriter);

        // Use reflection to replace Files.newBufferedWriter(Path, Charset) call indirectly
        // by creating a subclass of CSVFormat that overrides print(Path, Charset)
        // and returns CSVPrinter wrapping our BufferedWriter.

        CSVFormat csvFormatSpy = new CSVFormatWrapper(csvFormat, mockPath, StandardCharsets.UTF_8, bufferedWriter);

        CSVPrinter printer = csvFormatSpy.print(mockPath, StandardCharsets.UTF_8);

        assertNotNull(printer);
    }

    @Test
    void testPrint_withPath_throwsIOException_whenFilesNewBufferedWriterThrows() throws IOException {
        Path mockPath = mock(Path.class);

        CSVFormat csvFormatSpy = new CSVFormatWrapper(csvFormat, mockPath, StandardCharsets.UTF_8, null) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                if (out == mockPath && charset.equals(StandardCharsets.UTF_8)) {
                    throw new IOException("Test IOException");
                }
                return super.print(out, charset);
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> csvFormatSpy.print(mockPath, StandardCharsets.UTF_8));
        assertEquals("Test IOException", thrown.getMessage());
    }

    /**
     * Wrapper subclass for CSVFormat to override print(Path, Charset)
     * and avoid calling Files.newBufferedWriter by returning CSVPrinter on a provided BufferedWriter.
     */
    private static class CSVFormatWrapper extends CSVFormat {
        private final CSVFormat delegate;
        private final Path expectedPath;
        private final java.nio.charset.Charset expectedCharset;
        private final BufferedWriter bufferedWriter;

        CSVFormatWrapper(CSVFormat delegate, Path expectedPath, java.nio.charset.Charset expectedCharset, BufferedWriter bufferedWriter) {
            super(getField(delegate, "delimiter"),
                    getField(delegate, "quoteChar"),
                    getField(delegate, "quoteMode"),
                    getField(delegate, "commentStart"),
                    getField(delegate, "escape"),
                    getField(delegate, "ignoreSurroundingSpaces"),
                    getField(delegate, "ignoreEmptyLines"),
                    getField(delegate, "recordSeparator"),
                    getField(delegate, "nullString"),
                    getField(delegate, "headerComments"),
                    getField(delegate, "header"),
                    getField(delegate, "skipHeaderRecord"),
                    getField(delegate, "allowMissingColumnNames"),
                    getField(delegate, "ignoreHeaderCase"),
                    getField(delegate, "trim"),
                    getField(delegate, "trailingDelimiter"),
                    getField(delegate, "autoFlush"));
            this.delegate = delegate;
            this.expectedPath = expectedPath;
            this.expectedCharset = expectedCharset;
            this.bufferedWriter = bufferedWriter;
        }

        @Override
        public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
            if (out == expectedPath && charset.equals(expectedCharset)) {
                if (bufferedWriter == null) {
                    throw new IOException("Test IOException");
                }
                return print(bufferedWriter);
            }
            return delegate.print(out, charset);
        }

        @SuppressWarnings("unchecked")
        private static <T> T getField(CSVFormat instance, String fieldName) {
            try {
                Field f = CSVFormat.class.getDeclaredField(fieldName);
                f.setAccessible(true);
                return (T) f.get(instance);
            } catch (Exception e) {
                throw new RuntimeException(e);
            }
        }
    }
}
